{"code": "import json
import re

# Read the full result from the previous query
result_file = var_functions.query_db:12
if isinstance(result_file, str) and result_file.endswith('.json'):
    with open(result_file, 'r') as f:
        uc_patents = json.load(f)
else:
    uc_patents = var_functions.query_db:12

# Extract UNIV CALIFORNIA publication numbers
uc_pub_numbers = []
for patent in uc_patents:
    patents_info = patent.get('Patents_info', '')
    # Look for patterns like "pub. number XXXXX" or "publication number XXXXX"
    match = re.search(r'pub\. number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if not match:
        match = re.search(r'publication number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if match:
        pub_num = match.group(1)
        uc_pub_numbers.append(pub_num)

print('__RESULT__:')
print(json.dumps({
    'uc_patents_count': len(uc_patents),
    'uc_pub_numbers': uc_pub_numbers[:10],  # Show first 10
    'total_uc_pub_numbers': len(uc_pub_numbers)
}))"}

{"code": "import json
import re

# Access the result from storage using locals()
result_var = locals()['var_functions.query_db:12']

# Read the full result from the previous query
if isinstance(result_var, str) and result_var.endswith('.json'):
    with open(result_var, 'r') as f:
        uc_patents = json.load(f)
else:
    uc_patents = result_var

# Extract all UNIV CALIFORNIA publication numbers
uc_pub_numbers = set()
for patent in uc_patents:
    patents_info = patent.get('Patents_info', '')
    # Look for patterns like "pub. number XXXXX" or "publication number XXXXX"
    match = re.search(r'pub\. number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if not match:
        match = re.search(r'publication number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if match:
        pub_num = match.group(1)
        uc_pub_numbers.add(pub_num)

# Also try to extract from citation field patterns which might include publication numbers
for patent in uc_patents:
    citation = patent.get('citation', '')
    if citation and citation != '[]':
        try:
            citations = json.loads(citation) if isinstance(citation, str) else citation
            if isinstance(citations, list):
                for cite in citations:
                    pub_num = cite.get('publication_number')
                    if pub_num:
                        uc_pub_numbers.add(pub_num)
        except:
            pass

print('__RESULT__:')
print(json.dumps({
    'uc_patents_count': len(uc_patents),
    'total_unique_uc_pub_numbers': len(uc_pub_numbers),
    'uc_pub_numbers': list(uc_pub_numbers)
}))"}

{"code": "import json
import re

# Step 1: Extract all UNIV CALIFORNIA publication numbers
result_var = locals()['var_functions.query_db:12']

# Read the full result from the previous query
if isinstance(result_var, str) and result_var.endswith('.json'):
    with open(result_var, 'r') as f:
        uc_patents = json.load(f)
else:
    uc_patents = result_var

# Extract UNIV CALIFORNIA publication numbers and also track citation targets from their own citations
uc_pub_numbers = set()
cited_pub_numbers = set()

for patent in uc_patents:
    patents_info = patent.get('Patents_info', '')
    # Extract publication number for the UC patent itself
    match = re.search(r'pub\. number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if not match:
        match = re.search(r'publication number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if match:
        pub_num = match.group(1)
        uc_pub_numbers.add(pub_num)

    # Also extract what these UC patents cite (to understand patterns)
    citation_field = patent.get('citation', '')
    if citation_field and citation_field != '[]':
        try:
            citations = json.loads(citation_field) if isinstance(citation_field, str) else citation_field
            if isinstance(citations, list):
                for cite in citations:
                    pub_num = cite.get('publication_number')
                    if pub_num:
                        cited_pub_numbers.add(pub_num)
        except:
            pass

print('__RESULT__:')
print(json.dumps({
    'total_uc_publication_numbers': len(uc_pub_numbers),
    'total_cited_by_uc_patents': len(cited_pub_numbers),
    'uc_pub_numbers': list(uc_pub_numbers)
}))"}

