uc_publications_with_cpc_and_citations = {}  # UC patents that are cited, with their CPC codes

for patent in uc_patents:
    # Extract UC patent publication number
    patents_info = patent.get('Patents_info', '')
    uc_pub_match = re.search(r'pub\. number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if not uc_pub_match:
        uc_pub_match = re.search(r'publication number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)

    if uc_pub_match:
        uc_pub_num = uc_pub_match.group(1)
        # Get CPC codes for this UC patent
        cpc_json = patent.get('cpc', '[]')
        try:
            cpc_list = json.loads(cpc_json) if isinstance(cpc_json, str) else cpc_json
            uc_publications_with_cpc_and_citations[uc_pub_num] = {
                'cpc_codes': [],
                'cited_by': []
            }
            for cpc in cpc_list:
                code = cpc.get('code')
                if code:
                    uc_publications_with_cpc_and_citations[uc_pub_num]['cpc_codes'].append(code)
        except:
            uc_publications_with_cpc_and_citations[uc_pub_num] = {'cpc_codes': [], 'cited_by': []}

# Step 4: Check all patents to find which ones cite UC patents
for patent in all_patents:
    citation_field = patent.get('citation', '')
    patents_info = patent.get('Patents_info', '')

    if citation_field and citation_field != '[]':
        try:
            citations = json.loads(citation_field) if isinstance(citation_field, str) else citation_field
            if isinstance(citations, list):
                cited_uc_patents = []
