                    assignee_match = re.search(r'([A-Z][A-Z0-9\s\&\,\-\.]*\(?[A-Z][A-Z0-9\s\&\,\-\.]*\)?)(?:holds|hold|owns|is|the)\s+(?:patent|application|filing)', patents_info, re.IGNORECASE)
