{"code": "import json
import re

# Step 1: Load UC publication numbers from previous analysis
result_var = locals()['var_functions.query_db:12']

if isinstance(result_var, str) and result_var.endswith('.json'):
    with open(result_var, 'r') as f:
        uc_patents = json.load(f)
else:
    uc_patents = result_var

# Extract UNIV CALIFORNIA publication numbers
uc_pub_numbers = set()
for patent in uc_patents:
    patents_info = patent.get('Patents_info', '')
    match = re.search(r'pub\. number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if not match:
        match = re.search(r'publication number\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if match:
        pub_num = match.group(1)
        uc_pub_numbers.add(pub_num)

# Also extract UC application numbers for more comprehensive matching
uc_app_numbers = set()
for patent in uc_patents:
    patents_info = patent.get('Patents_info', '')
    match = re.search(r'application\s+\(?(?:no\.?|number)\s+([A-Z0-9\-]+)', patents_info, re.IGNORECASE)
    if match:
        uc_app_numbers.add(match.group(1))

print('__RESULT__:')
print(json.dumps({
    'uc_pub_numbers_count': len(uc_pub_numbers),
    'uc_app_numbers_count': len(uc_app_numbers),
    'sample_uc_pub_numbers': list(uc_pub_numbers)[:10]
}))"}

